-- Source business: 7fcae206-6c1c-4c32-81a2-109fe0015042
-- Prices are hints in KES and should be reviewed by the shop owner on adopt.

-- Replace prior global catalog seed (V122 hand-written data).
SET @catalog_id = '00000000-0000-0000-0000-000000000001';

UPDATE items i
INNER JOIN global_products gp ON gp.id = i.global_product_source_id
   SET i.global_product_source_id = NULL
 WHERE gp.catalog_id = @catalog_id;

DELETE gppi FROM global_product_pack_items gppi
INNER JOIN global_product_packs gpp ON gpp.id = gppi.pack_id
 WHERE gpp.catalog_id = @catalog_id;

DELETE FROM global_product_packs WHERE catalog_id = @catalog_id;

DELETE gpsl FROM global_product_supplier_links gpsl
INNER JOIN global_products gp ON gp.id = gpsl.global_product_id
 WHERE gp.catalog_id = @catalog_id;

DELETE FROM global_products WHERE catalog_id = @catalog_id;

DELETE FROM global_categories WHERE catalog_id = @catalog_id;

VALUES (@catalog_id, 'default', 'Kenya Retail Catalog', 'KE', 'KES', 'published', 2)
ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  region_code = VALUES(region_code),
  currency = VALUES(currency),
  status = VALUES(status),
  version = VALUES(version);

